  1→//! Live CRM service backed by the SQLite store.
  2→//!
  3→//! [`LiveCrmService`] implements [`moltis_service_traits::CrmService`] by
  4→//! delegating to [`moltis_crm::SqliteCrmStore`].  Each RPC method deserialises
  5→//! its `serde_json::Value` params, calls the appropriate store operation, and
  6→//! serialises the result back.
  7→//!
  8→//! PII fields (email, phone) are exposed in responses — callers reach this
  9→//! service only through the auth-gated WebSocket layer.
 10→
 11→use std::sync::Arc;
 12→
 13→use async_trait::async_trait;
 14→use moltis_crm::{
 15→    Contact, ContactChannel, Interaction, Matter, SqliteCrmStore, store::CrmStore,
 16→    types::{ContactStage, InteractionKind, MatterPhase, MatterStatus, PracticeArea},
 17→};
 18→use moltis_service_traits::{CrmService, ServiceError, ServiceResult};
 19→use secrecy::{ExposeSecret, Secret};
 20→use serde_json::Value;
 21→
 22→/// Live CRM service backed by a SQLite store.
 23→pub struct LiveCrmService {
 24→    store: Arc<SqliteCrmStore>,
 25→}
 26→
 27→impl LiveCrmService {
 28→    #[must_use]
 29→    pub fn new(store: Arc<SqliteCrmStore>) -> Self {
 30→        Self { store }
 31→    }
 32→}
 33→
 34→// ── Serialisation helpers ─────────────────────────────────────────────────────
 35→
 36→fn contact_to_json(c: Contact) -> Value {
 37→    serde_json::json!({
 38→        "id":         c.id,
 39→        "name":       c.name,
 40→        "source":     c.source,
 41→        "externalId": c.external_id,
 42→        "email":      c.email.as_ref().map(|s| s.expose_secret()),
 43→        "phone":      c.phone.as_ref().map(|s| s.expose_secret()),
 44→        "stage":      c.stage.as_str(),
 45→        "metadata":   c.metadata,
 46→        "createdAt":  c.created_at,
 47→        "updatedAt":  c.updated_at,
 48→    })
 49→}
 50→
 51→fn channel_to_json(ch: ContactChannel) -> Value {
 52→    serde_json::json!({
 53→        "id":          ch.id,
 54→        "contactId":   ch.contact_id,
 55→        "channelType": ch.channel_type,
 56→        "channelId":   ch.channel_id,
 57→        "displayName": ch.display_name,
 58→        "verified":    ch.verified,
 59→        "createdAt":   ch.created_at,
 60→        "updatedAt":   ch.updated_at,
 61→    })
 62→}
 63→
 64→fn matter_to_json(m: Matter) -> Value {
 65→    serde_json::json!({
 66→        "id":           m.id,
 67→        "contactId":    m.contact_id,
 68→        "title":        m.title,
 69→        "description":  m.description,
 70→        "status":       m.status.as_str(),
 71→        "phase":        m.phase.as_str(),
 72→        "practiceArea": m.practice_area.as_str(),
 73→        "createdAt":    m.created_at,
 74→        "updatedAt":    m.updated_at,
 75→    })
 76→}
 77→
 78→fn interaction_to_json(i: Interaction) -> Value {
 79→    serde_json::json!({
 80→        "id":        i.id,
 81→        "contactId": i.contact_id,
 82→        "matterId":  i.matter_id,
 83→        "kind":      i.kind.as_str(),
 84→        "summary":   i.summary,
 85→        "channel":   i.channel,
 86→        "createdAt": i.created_at,
 87→        "updatedAt": i.updated_at,
 88→    })
 89→}
 90→
 91→fn store_err(e: moltis_crm::Error) -> ServiceError {
 92→    ServiceError::message(e.to_string())
 93→}
 94→
 95→// ── CrmService impl ───────────────────────────────────────────────────────────
 96→
 97→#[async_trait]
 98→impl CrmService for LiveCrmService {
 99→    // ── Contacts ──────────────────────────────────────────────────────────────
100→
101→    async fn list_contacts(&self) -> ServiceResult {
102→        let contacts = self.store.list().await.map_err(store_err)?;
103→        Ok(Value::Array(contacts.into_iter().map(contact_to_json).collect()))
104→    }
105→
106→    async fn get_contact(&self, params: Value) -> ServiceResult {
107→        let id = require_str(&params, "id")?;
108→        let contact = self.store.get(id).await.map_err(store_err)?;
109→        Ok(contact.map(contact_to_json).unwrap_or(Value::Null))
110→    }
111→
112→    async fn upsert_contact(&self, params: Value) -> ServiceResult {
113→        let contact = parse_contact(params)?;
114→        self.store.upsert(contact).await.map_err(store_err)?;
115→        Ok(serde_json::json!({ "ok": true }))
116→    }
117→
118→    async fn delete_contact(&self, params: Value) -> ServiceResult {
119→        let id = require_str(&params, "id")?;
120→        self.store.delete(id).await.map_err(store_err)?;
121→        Ok(serde_json::json!({ "ok": true }))
122→    }
123→
124→    // ── Contact channels ──────────────────────────────────────────────────────
125→
126→    async fn list_channels(&self, params: Value) -> ServiceResult {
127→        let contact_id = require_str(&params, "contactId")?;
128→        let channels = self
129→            .store
130→            .list_channels_for_contact(contact_id)
131→            .await
132→            .map_err(store_err)?;
133→        Ok(Value::Array(channels.into_iter().map(channel_to_json).collect()))
134→    }
135→
136→    async fn upsert_channel(&self, params: Value) -> ServiceResult {
137→        let channel = parse_channel(params)?;
138→        self.store.upsert_channel(channel).await.map_err(store_err)?;
139→        Ok(serde_json::json!({ "ok": true }))
140→    }
141→
142→    async fn delete_channel(&self, params: Value) -> ServiceResult {
143→        let id = require_str(&params, "id")?;
144→        self.store.delete_channel(id).await.map_err(store_err)?;
145→        Ok(serde_json::json!({ "ok": true }))
146→    }
147→
148→    // ── Matters ───────────────────────────────────────────────────────────────
149→
150→    async fn list_matters(&self) -> ServiceResult {
151→        let matters = self.store.list_matters().await.map_err(store_err)?;
152→        Ok(Value::Array(matters.into_iter().map(matter_to_json).collect()))
153→    }
154→
155→    async fn get_matter(&self, params: Value) -> ServiceResult {
156→        let id = require_str(&params, "id")?;
157→        let matter = self.store.get_matter(id).await.map_err(store_err)?;
158→        Ok(matter.map(matter_to_json).unwrap_or(Value::Null))
159→    }
160→
161→    async fn upsert_matter(&self, params: Value) -> ServiceResult {
162→        let matter = parse_matter(params)?;
163→        self.store.upsert_matter(matter).await.map_err(store_err)?;
164→        Ok(serde_json::json!({ "ok": true }))
165→    }
166→
167→    async fn delete_matter(&self, params: Value) -> ServiceResult {
168→        let id = require_str(&params, "id")?;
169→        self.store.delete_matter(id).await.map_err(store_err)?;
170→        Ok(serde_json::json!({ "ok": true }))
171→    }
172→
173→    // ── Interactions ──────────────────────────────────────────────────────────
174→
175→    async fn list_interactions(&self, params: Value) -> ServiceResult {
176→        if let Some(contact_id) = params.get("contactId").and_then(|v| v.as_str()) {
177→            let items = self
178→                .store
179→                .list_interactions_by_contact(contact_id)
180→                .await
181→                .map_err(store_err)?;
182→            return Ok(Value::Array(items.into_iter().map(interaction_to_json).collect()));
183→        }
184→        if let Some(matter_id) = params.get("matterId").and_then(|v| v.as_str()) {
185→            let items = self
186→                .store
187→                .list_interactions_by_matter(matter_id)
188→                .await
189→                .map_err(store_err)?;
190→            return Ok(Value::Array(items.into_iter().map(interaction_to_json).collect()));
191→        }
192→        Err(ServiceError::message(
193→            "list_interactions requires contactId or matterId",
194→        ))
195→    }
196→
197→    async fn get_interaction(&self, params: Value) -> ServiceResult {
198→        let id = require_str(&params, "id")?;
199→        let item = self.store.get_interaction(id).await.map_err(store_err)?;
200→        Ok(item.map(interaction_to_json).unwrap_or(Value::Null))
201→    }
202→
203→    async fn upsert_interaction(&self, params: Value) -> ServiceResult {
204→        let interaction = parse_interaction(params)?;
205→        self.store
206→            .upsert_interaction(interaction)
207→            .await
208→            .map_err(store_err)?;
209→        Ok(serde_json::json!({ "ok": true }))
210→    }
211→
212→    async fn delete_interaction(&self, params: Value) -> ServiceResult {
213→        let id = require_str(&params, "id")?;
214→        self.store.delete_interaction(id).await.map_err(store_err)?;
215→        Ok(serde_json::json!({ "ok": true }))
216→    }
217→}
218→
219→// ── Parse helpers ─────────────────────────────────────────────────────────────
220→
221→fn require_str<'a>(params: &'a Value, field: &'static str) -> Result<&'a str, ServiceError> {
222→    params
223→        .get(field)
224→        .and_then(|v| v.as_str())
225→        .ok_or_else(|| ServiceError::message(format!("missing field: {field}")))
226→}
227→
228→fn parse_contact(p: Value) -> Result<Contact, ServiceError> {
229→    let id = require_str(&p, "id")?.to_owned();
230→    let name = require_str(&p, "name")?.to_owned();
231→    let stage = p
232→        .get("stage")
233→        .and_then(|v| v.as_str())
234→        .unwrap_or("lead")
235→        .parse::<ContactStage>()
236→        .map_err(ServiceError::message)?;
237→    let now = now_ms();
238→    Ok(Contact {
239→        id,
240→        name,
241→        source: p.get("source").and_then(|v| v.as_str()).map(ToOwned::to_owned),
242→        external_id: p
243→            .get("externalId")
244→            .and_then(|v| v.as_str())
245→            .map(ToOwned::to_owned),
246→        email: p
247→            .get("email")
248→            .and_then(|v| v.as_str())
249→            .map(|s| Secret::new(s.to_owned())),
250→        phone: p
251→            .get("phone")
252→            .and_then(|v| v.as_str())
253→            .map(|s| Secret::new(s.to_owned())),
254→        stage,
255→        metadata: p
256→            .get("metadata")
257→            .cloned()
258→            .unwrap_or_else(|| serde_json::json!({})),
259→        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
260→        updated_at: now,
261→    })
262→}
263→
264→fn parse_channel(p: Value) -> Result<ContactChannel, ServiceError> {
265→    let id = require_str(&p, "id")?.to_owned();
266→    let contact_id = require_str(&p, "contactId")?.to_owned();
267→    let channel_type = require_str(&p, "channelType")?.to_owned();
268→    let channel_id = require_str(&p, "channelId")?.to_owned();
269→    let now = now_ms();
270→    Ok(ContactChannel {
271→        id,
272→        contact_id,
273→        channel_type,
274→        channel_id,
275→        display_name: p
276→            .get("displayName")
277→            .and_then(|v| v.as_str())
278→            .map(ToOwned::to_owned),
279→        verified: p.get("verified").and_then(|v| v.as_bool()).unwrap_or(false),
280→        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
281→        updated_at: now,
282→    })
283→}
284→
285→fn parse_matter(p: Value) -> Result<Matter, ServiceError> {
286→    let id = require_str(&p, "id")?.to_owned();
287→    let title = require_str(&p, "title")?.to_owned();
288→    let status = p
289→        .get("status")
290→        .and_then(|v| v.as_str())
291→        .unwrap_or("open")
292→        .parse::<MatterStatus>()
293→        .map_err(ServiceError::message)?;
294→    let phase = p
295→        .get("phase")
296→        .and_then(|v| v.as_str())
297→        .unwrap_or("intake")
298→        .parse::<MatterPhase>()
299→        .map_err(ServiceError::message)?;
300→    let practice_area = p
301→        .get("practiceArea")
302→        .and_then(|v| v.as_str())
303→        .unwrap_or("other")
304→        .parse::<PracticeArea>()
305→        .map_err(ServiceError::message)?;
306→    let now = now_ms();
307→    Ok(Matter {
308→        id,
309→        contact_id: p
310→            .get("contactId")
311→            .and_then(|v| v.as_str())
312→            .map(ToOwned::to_owned),
313→        title,
314→        description: p
315→            .get("description")
316→            .and_then(|v| v.as_str())
317→            .map(ToOwned::to_owned),
318→        status,
319→        phase,
320→        practice_area,
321→        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
322→        updated_at: now,
323→    })
324→}
325→
326→fn parse_interaction(p: Value) -> Result<Interaction, ServiceError> {
327→    let id = require_str(&p, "id")?.to_owned();
328→    let contact_id = require_str(&p, "contactId")?.to_owned();
329→    let kind = require_str(&p, "kind")?
330→        .parse::<InteractionKind>()
331→        .map_err(ServiceError::message)?;
332→    let summary = require_str(&p, "summary")?.to_owned();
333→    let now = now_ms();
334→    Ok(Interaction {
335→        id,
336→        contact_id,
337→        matter_id: p
338→            .get("matterId")
339→            .and_then(|v| v.as_str())
340→            .map(ToOwned::to_owned),
341→        kind,
342→        summary,
343→        channel: p
344→            .get("channel")
345→            .and_then(|v| v.as_str())
346→            .map(ToOwned::to_owned),
347→        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
348→        updated_at: now,
349→    })
350→}
351→
352→fn now_ms() -> u64 {
353→    use std::time::{SystemTime, UNIX_EPOCH};
354→    SystemTime::now()
355→        .duration_since(UNIX_EPOCH)
356→        .unwrap_or_default()
357→        .as_millis() as u64
358→}
